/**
 * @test Sem_Init_ValidParameters_Success
 * @brief 测试正常初始化信号量
 * @details 验证信号量初始化后所有字段是否正确设置
 * @Given 有效的信号量指针、名称和初始值
 * @When 调用 mrtk_sem_init()
 * @Then 返回 MRTK_EOK，信号量值正确设置
 */
TEST_F(MrtkSemTest, Sem_Init_ValidParameters_Success) {
    // Step 1: Given - 准备有效的信号量对象和参数
    const mrtk_char_t *sem_name = "TestSem";
    mrtk_u16_t initial_value = 5;
    mrtk_u8_t flag = MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO;

    // Step 2: When - 执行初始化
    mrtk_err_t ret = mrtk_sem_init(&test_sem_static, sem_name, initial_value, flag);

    // Step 3: Then - 验证返回值和信号量值
    EXPECT_EQ(ret, MRTK_EOK);
    verify_sem_value(&test_sem_static, initial_value);
}

