/**
 * @test Sem_Detach_ValidSem_Success
 * @brief 测试正常脱离信号量
 * @details 验证脱离静态信号量后的状态
 * @Given 已初始化的静态信号量
 * @When 调用 mrtk_sem_detach()
 * @Then 返回 MRTK_EOK，所有等待任务被唤醒并设置错误码
 */
TEST_F(MrtkSemTest, Sem_Detach_ValidSem_Success) {
    // Step 1: Given - 初始化信号量
    mrtk_sem_init(&test_sem_static, "TestSem", 1,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 脱离信号量
    mrtk_err_t ret = mrtk_sem_detach(&test_sem_static);

    // Step 3: Then - 验证返回值
    EXPECT_EQ(ret, MRTK_EOK);
}

/**
 * @test Sem_Detach_WithWaitingTasks_TasksResumedWithError
 * @brief 测试脱离有等待任务的信号量
 * @details 验证脱离时唤醒所有等待任务并设置 MRTK_EDELETED 错误码
 * @Given 已初始化的信号量，且有任务在等待队列中
 * @When 调用 mrtk_sem_detach()
 * @Then 所有等待任务被唤醒，last_error 设置为 MRTK_EDELETED
 */
TEST_F(MrtkSemTest, Sem_Detach_WithWaitingTasks_TasksResumedWithError) {
    // Step 1: Given - 初始化信号量，并有任务在等待队列中
    mrtk_sem_init(&test_sem_static, "TestSem", 0,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 将高优先级任务挂起到信号量的等待队列
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_high.sched_node);

    // 将中优先级任务也挂起到等待队列
    make_task_suspend(&task_mid);
    task_mid.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_mid.sched_node);

    // Step 2: When - 脱离信号量
    mrtk_err_t ret = mrtk_sem_detach(&test_sem_static);

    // Step 3: Then - 验证返回值和任务状态
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.last_error, MRTK_EDELETED);
    EXPECT_EQ(task_mid.last_error, MRTK_EDELETED);
}

