/**
 * @test Sem_Release_WithWaitingTasks_WakeupOneTask
 * @brief 测试释放时有等待任务的情况
 * @details 验证释放时唤醒一个等待任务，资源计数不变
 * @Given 信号量有任务在等待队列中
 * @When 调用 mrtk_sem_release()
 * @Then 等待队列中的一个任务被唤醒，资源计数不变（直接移交）
 */
TEST_F(MrtkSemTest, Sem_Release_WithWaitingTasks_WakeupOneTask) {
    // Step 1: Given - 信号量无资源，有任务等待
    mrtk_sem_init(&test_sem_static, "TestSem", 0,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // 将高优先级任务挂起到等待队列
    make_task_suspend(&task_high);
    task_high.last_error = MRTK_EOK;
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_high.sched_node);

    // Step 2: When - 释放信号量
    mrtk_err_t ret = mrtk_sem_release(&test_sem_static);

    // Step 3: Then - 验证高优先级任务被唤醒，资源计数不变
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.state, MRTK_TASK_STAT_READY); /* 被唤醒 */
    verify_sem_value(&test_sem_static, 0); /* 直接移交，不变 */
}

/**
 * @test Sem_Release_MultipleWaitingTasks_WakeupHighestPriority
 * @brief 测试 PRIO 策略下唤醒最高优先级任务
 * @details 验证按优先级唤醒机制
 * @Given PRIO 策略信号量，多个任务在等待队列
 * @When 调用 mrtk_sem_release()
 * @Then 最高优先级任务被唤醒
 */
/**
 * @test Sem_Release_MultipleWaitingTasks_WakeupHighestPriority
 * @brief 测试 PRIO 策略下优先级最高的任务被唤醒
 * @details Given PRIO 策略信号量，多个任务在等待队列
 *          When 调用 mrtk_sem_release()
 *          Then 优先级最高的任务被唤醒
 * @note 使用 _mrtk_ipc_suspend_one 模拟任务阻塞，避免依赖任务调度器
 */
TEST_F(MrtkSemTest, Sem_Release_MultipleWaitingTasks_WakeupHighestPriority) {
    // Step 1: Given - PRIO 策略信号量，多个任务等待
    mrtk_sem_init(&test_sem_static, "TestSem", 0,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    /*
     * 模拟 PRIO 策略下的任务阻塞场景：
     * - _mrtk_ipc_suspend_one() 会根据 flag 参数（FIFO/PRIO）决定插入位置
     * - PRIO 策略会按优先级从高到低排序等待队列
     * - 无论插入顺序如何，最终链表都是 [high, mid, low]
     */
    make_task_suspend(&task_mid);
    _mrtk_ipc_suspend_one(&test_sem_static.ipc_obj.suspend_taker,
                          test_sem_static.ipc_obj.flag, &task_mid);

    make_task_suspend(&task_low);
    _mrtk_ipc_suspend_one(&test_sem_static.ipc_obj.suspend_taker,
                          test_sem_static.ipc_obj.flag, &task_low);

    make_task_suspend(&task_high);
    _mrtk_ipc_suspend_one(&test_sem_static.ipc_obj.suspend_taker,
                          test_sem_static.ipc_obj.flag, &task_high);

    // Step 2: When - 释放信号量
    mrtk_err_t ret = mrtk_sem_release(&test_sem_static);

    // Step 3: Then - 验证最高优先级任务被唤醒
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.state, MRTK_TASK_STAT_READY);
}

/**
 * @test Sem_Release_FIFO_WaitingOrder_FIFOWakeup
 * @brief 测试 FIFO 策略下的唤醒顺序
 * @details 验证 FIFO 策略按等待顺序唤醒
 * @Given FIFO 策略信号量，多个任务在等待队列
 * @When 调用 mrtk_sem_release()
 * @Then 按照等待顺序（先来先得）唤醒任务
 */
TEST_F(MrtkSemTest, Sem_Release_FIFO_WaitingOrder_FIFOWakeup) {
    // Step 1: Given - FIFO 策略信号量，多个任务按顺序等待
    mrtk_sem_init(&test_sem_static, "TestSem", 0,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_FIFO);

    // 按顺序插入任务
    make_task_suspend(&task_high);
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_high.sched_node);

    make_task_suspend(&task_mid);
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_mid.sched_node);

    make_task_suspend(&task_low);
    _mrtk_list_insert_before(&test_sem_static.ipc_obj.suspend_taker,
                          &task_low.sched_node);

    // Step 2: When - 释放信号量
    mrtk_err_t ret = mrtk_sem_release(&test_sem_static);

    // Step 3: Then - 验证第一个等待者（高优先级任务）被唤醒
    EXPECT_EQ(ret, MRTK_EOK);
    EXPECT_EQ(task_high.state, MRTK_TASK_STAT_READY);
}

