/* ==============================================================================
 * 综合场景测试
 * ============================================================================== */

/**
 * @test Sem_BinarySemaphore_ProducerConsumer
 * @brief 测试二值信号量用于生产者-消费者同步
 * @details 验证信号量作为同步原语（value = 0/1）
 * @Given 二值信号量（初始值 0）
 * @When 生产者 release，消费者 take
 * @then 同步正常工作
 */
TEST_F(MrtkSemTest, Sem_BinarySemaphore_ProducerConsumer) {
    // Step 1: Given - 二值信号量（初始值 0）
    mrtk_sem_init(&test_sem_static, "BinarySem", 0,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 生产者释放（从 0 到 1）
    mrtk_err_t ret_release = mrtk_sem_release(&test_sem_static);
    ASSERT_EQ(ret_release, MRTK_EOK);
    verify_sem_value(&test_sem_static, 1);

    // 消费者获取（从 1 到 0）
    mrtk_err_t ret_take = mrtk_sem_take(&test_sem_static, 0);

    // Step 3: Then - 验证同步成功
    EXPECT_EQ(ret_take, MRTK_EOK);
    verify_sem_value(&test_sem_static, 0);
}

/**
 * @test Sem_CountingSemaphore_ResourcePool
 * @brief 测试计数信号量用于资源池管理
 * @details 验证多个资源的获取和释放
 * @Given 计数信号量（初始值 = 资源数量）
 * @When 多次 take 和 release
 * @then 资源计数正确维护
 */
TEST_F(MrtkSemTest, Sem_CountingSemaphore_ResourcePool) {
    // Step 1: Given - 计数信号量（资源池大小为 5）
    mrtk_u16_t pool_size = 5;
    mrtk_sem_init(&test_sem_static, "ResourcePool", pool_size,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 获取 3 个资源
    for (mrtk_u16_t i = 0; i < 3; ++i) {
        mrtk_err_t ret = mrtk_sem_take(&test_sem_static, 0);
        ASSERT_EQ(ret, MRTK_EOK);
    }
    verify_sem_value(&test_sem_static, 2); /* 5 - 3 = 2 */

    // 释放 1 个资源
    mrtk_err_t ret_release = mrtk_sem_release(&test_sem_static);
    ASSERT_EQ(ret_release, MRTK_EOK);

    // Step 3: Then - 验证资源计数正确
    verify_sem_value(&test_sem_static, 3); /* 2 + 1 = 3 */
}

/**
 * @test Sem_CompleteLifecycle_InitTakeReleaseDetach_Success
 * @brief 测试信号量完整生命周期
 * @details 验证 Init → Take → Release → Detach 的完整流程
 * @Given 信号量对象
 * @When 依次执行 init, take, release, detach
 * @Then 每一步都成功返回
 */
TEST_F(MrtkSemTest, Sem_CompleteLifecycle_InitTakeReleaseDetach_Success) {
    // Step 1: Given - 信号量对象和任务

    // Step 2: When - 执行完整生命周期
    mrtk_err_t ret_init = mrtk_sem_init(&test_sem_static, "LifecycleSem", 1,
                                         MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    mrtk_err_t ret_take = mrtk_sem_take(&test_sem_static, 100);
    mrtk_err_t ret_release = mrtk_sem_release(&test_sem_static);
    mrtk_err_t ret_detach = mrtk_sem_detach(&test_sem_static);

    // Step 3: Then - 验证每一步都成功
    EXPECT_EQ(ret_init, MRTK_EOK);
    EXPECT_EQ(ret_take, MRTK_EOK);
    EXPECT_EQ(ret_release, MRTK_EOK);
    EXPECT_EQ(ret_detach, MRTK_EOK);
}

/**
 * @test Sem_ResourceExhaustion_AllResourcesTaken
 * @brief 测试资源耗尽场景
 * @details 验证所有资源都被获取后，再获取会阻塞
 * @Given 信号量有 N 个资源
 * @When 获取 N+1 次
 * @Then 第 N+1 次获取会失败或阻塞
 */
TEST_F(MrtkSemTest, Sem_ResourceExhaustion_AllResourcesTaken) {
    // Step 1: Given - 信号量有 2 个资源
    mrtk_u16_t pool_size = 2;
    mrtk_sem_init(&test_sem_static, "ResourcePool", pool_size,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 获取所有资源
    mrtk_err_t ret1 = mrtk_sem_take(&test_sem_static, 0);
    mrtk_err_t ret2 = mrtk_sem_take(&test_sem_static, 0);

    // 第 3 次获取应失败（非阻塞模式）
    mrtk_err_t ret3 = mrtk_sem_take(&test_sem_static, 0);

    // Step 3: Then - 验证前两次成功，第三次失败
    EXPECT_EQ(ret1, MRTK_EOK);
    EXPECT_EQ(ret2, MRTK_EOK);
    EXPECT_EQ(ret3, MRTK_ERROR);
    verify_sem_value(&test_sem_static, 0);
}

/**
 * @test Sem_InterruptContext_NonBlockingOperations_Only
 * @brief 测试中断上下文中的信号量操作限制
 * @details 验证中断中只能进行非阻塞操作
 * @Given 在中断上下文中
 * @When 尝试阻塞操作 vs 非阻塞操作
 * @Then 阻塞操作返回错误，非阻塞操作成功
 */
TEST_F(MrtkSemTest, Sem_InterruptContext_NonBlockingOperations_Only) {
    // Step 1: Given - 中断上下文
    set_interrupt_nest(1);
    mrtk_sem_init(&test_sem_static, "TestSem", 1,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);
    set_current_task(&task_high);
    make_task_ready(&task_high);

    // Step 2: When - 在中断中尝试各种操作
    mrtk_err_t ret_nonblock = mrtk_sem_take(&test_sem_static, 0); /* 允许 */
    mrtk_err_t ret_block    = mrtk_sem_take(&test_sem_static, 100); /* 禁止 */
    mrtk_err_t ret_release  = mrtk_sem_release(&test_sem_static); /* 允许 */

    // Step 3: Then - 验证结果
    EXPECT_EQ(ret_nonblock, MRTK_EOK);
    EXPECT_EQ(ret_block, MRTK_E_IN_ISR);
    EXPECT_EQ(ret_release, MRTK_EOK);

    // 恢复中断嵌套
    set_interrupt_nest(0);
}

/**
 * @test Sem_ConcurrentAccess_MultipleTasks
 * @brief 测试多任务并发访问信号量
 * @details 验证信号量在多任务环境下的正确性
 * @Given 多个任务同时访问信号量
 * @When 各任务进行 take/release 操作
 * @Then 资源计数正确，无竞态条件
 */
TEST_F(MrtkSemTest, Sem_ConcurrentAccess_MultipleTasks) {
    // Step 1: Given - 初始化信号量，资源计数为 2
    mrtk_sem_init(&test_sem_static, "ConcurrentSem", 2,
                  MRTK_IPC_FLAG_NOTIFY_POLICY_PRIO);

    // Step 2: When - 模拟多任务访问
    // 高优先级任务获取资源
    set_current_task(&task_high);
    make_task_ready(&task_high);
    mrtk_err_t ret1 = mrtk_sem_take(&test_sem_static, 0);
    ASSERT_EQ(ret1, MRTK_EOK);

    // 中优先级任务获取资源
    set_current_task(&task_mid);
    make_task_ready(&task_mid);
    mrtk_err_t ret2 = mrtk_sem_take(&test_sem_static, 0);
    ASSERT_EQ(ret2, MRTK_EOK);

    // 低优先级任务尝试获取（应失败）
    set_current_task(&task_low);
    make_task_ready(&task_low);
    mrtk_err_t ret3 = mrtk_sem_take(&test_sem_static, 0);

    // Step 3: Then - 验证资源耗尽
    EXPECT_EQ(ret3, MRTK_ERROR);
    verify_sem_value(&test_sem_static, 0);
}

